// Birthday month/day (year auto-rolls to the next upcoming one)
const BIRTHDAY_MONTH = 9;  // September
const BIRTHDAY_DAY   = 9;

// The 5 balloon reasons — replace "img" with a real photo URL to show it,
// leave as null to keep the placeholder "add your photo here" box.
const balloonData = [
  { img: "data:image/jpeg;base64,", message:"The way you laugh with your whole face, like happiness was made just for moments like those."},
  { img: "data:image/jpeg;base64,", message: "The way you make every conversation feel lighter, every bad day feel smaller, and every memory worth keeping." },
  { img: "data:image/jpeg;base64,", message: "Thank you for turning ordinary moments into memories I'll never stop smiling about." },
  { img: "data:image/jpeg;base64,", message: "No matter how busy life gets, you'll always be one of my favorite people." },
  { img: "data:image/jpeg;base64,", message: "Thank you for being the kind of person who makes life feel a little less complicated and a lot more beautiful." }
];

// The wish text revealed after the candle is blown out
const wishMessage = "Wherever this next year takes you, I hope it hands you exactly what you've been quietly hoping for.";

/* ========================================================= */

// --- Countdown ---
function getNextBirthday(){
  const now = new Date();
  let year = now.getFullYear();
  let target = new Date(year, BIRTHDAY_MONTH - 1, BIRTHDAY_DAY, 0, 0, 0);
  if (target.getTime() <= now.getTime()){
    target = new Date(year + 1, BIRTHDAY_MONTH - 1, BIRTHDAY_DAY, 0, 0, 0);
  }
  return target;
}

function pad(n){ return n.toString().padStart(2,'0'); }

function updateCountdown(){
  const now = new Date();
  const target = getNextBirthday();
  let diff = target.getTime() - now.getTime();
  if (diff < 0) diff = 0;

  const days = Math.floor(diff / (1000*60*60*24));
  const hours = Math.floor((diff / (1000*60*60)) % 24);
  const mins = Math.floor((diff / (1000*60)) % 60);
  const secs = Math.floor((diff / 1000) % 60);

  document.getElementById('cd-days').textContent = pad(days);
  document.getElementById('cd-hours').textContent = pad(hours);
  document.getElementById('cd-mins').textContent = pad(mins);
  document.getElementById('cd-secs').textContent = pad(secs);
}
updateCountdown();
setInterval(updateCountdown, 1000);

// --- Balloons ---
const balloonRow = document.getElementById('balloonRow');
const balloonClasses = ['b1','b2','b3','b4','b5'];

balloonData.forEach((data, i) => {
  const wrap = document.createElement('div');
  wrap.className = 'balloon-wrap';
  wrap.innerHTML = `
    <button class="balloon ${balloonClasses[i]}" aria-label="reason ${i+1}"></button>
  `;
  const btn = wrap.querySelector('.balloon');
  btn.addEventListener('click', () => openModal(data, btn));
  balloonRow.appendChild(wrap);
});

const modalOverlay = document.getElementById('modalOverlay');
const modalPhoto = document.getElementById('modalPhoto');
const modalMessage = document.getElementById('modalMessage');
const modalClose = document.getElementById('modalClose');

function openModal(data, btnEl){
  if (data.img){
    modalPhoto.innerHTML = `<img src="${data.img}" alt="photo">`;
  } else {
    modalPhoto.innerHTML = `<div class="heart-icon">📷</div><div>add your photo here</div>`;
  }
  modalMessage.textContent = data.message;
  modalOverlay.classList.add('active');
  if (btnEl) btnEl.classList.add('popped');
}

function closeModal(){
  modalOverlay.classList.remove('active');
  document.querySelectorAll('.balloon.popped').forEach(b => b.classList.remove('popped'));
}

modalClose.addEventListener('click', closeModal);
modalOverlay.addEventListener('click', (e) => { if (e.target === modalOverlay) closeModal(); });

// --- Candle ---
const flame = document.getElementById('flame');
const smoke = document.getElementById('smoke');
const wishText = document.getElementById('wishText');
const cakeHint = document.getElementById('cakeHint');
wishText.textContent = wishMessage;

let blownOut = false;
flame.addEventListener('click', () => {
  if (blownOut) return;
  blownOut = true;
  flame.classList.add('out');
  smoke.classList.add('show');
  cakeHint.textContent = 'wish made ♡';
  setTimeout(() => wishText.classList.add('show'), 400);
});

// --- Ambient floating hearts on hero ---
const heroSection = document.getElementById('hero');
const heartSymbols = ['♡','♥'];
for (let i=0;i<10;i++){
  const h = document.createElement('div');
  h.className = 'heart-float';
  h.textContent = heartSymbols[Math.floor(Math.random()*heartSymbols.length)];
  h.style.left = Math.random()*90 + '%';
  h.style.top = Math.random()*80 + '%';
  h.style.animationDelay = (Math.random()*4) + 's';
  h.style.fontSize = (10 + Math.random()*10) + 'px';
  heroSection.appendChild(h);
}

// --- Continuous floating hearts across the whole page (background layer) ---
const bgAnimation = document.getElementById('bgAnimation');
const bgHeartSymbols = ['♡','♥','💕','💗'];
const MAX_BG_HEARTS = 16;

function spawnBgHeart(){
  if (bgAnimation.querySelectorAll('.bg-heart').length >= MAX_BG_HEARTS) return;
  const h = document.createElement('div');
  h.className = 'bg-heart';
  h.textContent = bgHeartSymbols[Math.floor(Math.random()*bgHeartSymbols.length)];
  const size = 12 + Math.random()*16;
  const duration = 10 + Math.random()*10;
  h.style.left = Math.random()*100 + '%';
  h.style.fontSize = size + 'px';
  h.style.animationDuration = duration + 's';
  bgAnimation.appendChild(h);
  setTimeout(() => h.remove(), duration*1000 + 200);
}

// seed a few immediately, then keep spawning
for (let i=0;i<6;i++){
  setTimeout(spawnBgHeart, i*600);
}
setInterval(spawnBgHeart, 1400);
